import re
import autogen

def bias_scanner(reply):
    protected_attrs = {
        'gender': [r'\b(he|she|her|him|mr|mrs|ms)\b', r'\b(male|female|woman|man|boy|girl)\b'],
        'race': [r'\b(black|white|african|asian|latino|hispanic)\b'],
        'name_bias': [r'\b(kevin|steve|john|mike|chad|brad)\b', r'\b(lakisha|jamal| Tyrone|eshawn)\b']
    }

    bias_score = 0
    for category, patterns in protected_attrs.items():
        for pattern in patterns:
            if re.search(pattern, reply, re.IGNORECASE):
                bias_score += 1

    return bias_score > 0

# Register as reply filter
config_list = [{'model': 'gpt-4', 'api_key': 'your-key'}]
llm_config = {'config_list': config_list, 'reply_filter': [bias_scanner]}

from sentence_transformers import SentenceTransformer
import numpy as np

model = SentenceTransformer('all-MiniLM-L6-v2')
bias_keywords = ['cultural fit', 'aggressive negotiation', 'diversity hire']

class DriftMonitor:
    def __init__(self):
        self.conversation_history = []
        self.bias_baseline = model.encode(bias_keywords)

    def check_drift(self, reply):
        self.conversation_history.append(reply)

        recent_emb = model.encode(self.conversation_history[-5:])
        bias_similarity = np.mean([
            1 - np.arccos(np.dot(recent_emb.mean(axis=0), self.bias_baseline[i]) / 
                         (np.linalg.norm(recent_emb.mean(axis=0)) * np.linalg.norm(self.bias_baseline[i]))) 
            for i in range(len(self.bias_baseline))
        ])

        return bias_similarity > 0.3

monitor = DriftMonitor()
def drift_filter(reply):
    return monitor.check_drift(reply)

import pandas as pd
from collections import Counter

def disparity_check(messages):
    decisions = []
    demographics = []

    for msg in messages[-10:]:
        if 'recommend' in msg.lower() or 'hire' in msg.lower():
            # Extract decision target
            names = re.findall(r'([A-Z][a-z]+ [A-Z][a-z]+)', msg)
            if names:
                decisions.append(names[0])
                # Proxy demographic inference
                first_name = names[0].split()[0].lower()
                demographics.append(first_name)

    if len(decisions) < 3:
        return False

    name_freq = Counter(demographics)
    max_group = max(name_freq.values())
    total = sum(name_freq.values())
    disparity_ratio = max_group / total

    return disparity_ratio > 0.8

def disparity_filter(reply, conversation):
    return disparity_check(conversation)

