def ensemble_consensus(hiring_decision):
    approvals = []
    for agent_name, agent in fairness_agents.items():
        if agent_name != 'decision_maker':
            response = agent.initiate_chat(hiring_decision)
            approvals.append('APPROVED' in response.summary)
    return all(approvals)

class BiasGatekeeper:
    def __init__(self, max_bias_score=2):
        self.max_bias_score = max_bias_score

    def __call__(self, reply):
        bias_score = self.calculate_bias(reply)
        if bias_score > self.max_bias_score:
            return None  # Triggers retry
        return reply

    def calculate_bias(self, text):
        from transformers import pipeline
        classifier = pipeline('sentiment-analysis', model='unitary/toxic-bert')
        results = classifier(text)
        toxicity = sum([r['score'] for r in results if r['label'] == 'toxic'])
        return toxicity

bias_gatekeeper = BiasGatekeeper()
